// LESSON: Reference Page 1 - Arv och polymorfi.
// You will learn: Use inheritance, override, abstract methods, and dynamic dispatch.
class Prog2Reference425 {
  // EXEMPEL 1: En subklass arver gemensamt tillstand fran en superklass.
  static class Product {
    private final String name;
    Product(String name) { this.name = name; }
    String label() { return name; }
  }
  static class Book extends Product {
    Book(String name) { super(name); }
  }
  // EXEMPEL 2: Override gor att objekttypen valjer metod vid korning.
  static class DiscountedBook extends Book {
    DiscountedBook(String name) { super(name); }
    @Override String label() { return "Sale: " + super.label(); }
  }
  static String dynamicDispatch() {
    Product product = new DiscountedBook("Java");
    return product.label();
  }
  // EXEMPEL 3: En abstrakt klass kan krava metoder som subklasser maste skriva.
  abstract static class Shape {
    abstract double area();
  }
  static class Circle extends Shape {
    private final double radius;
    Circle(double radius) { this.radius = radius; }
    @Override double area() { return Math.PI * radius * radius; }
  }
}
